settings.custom_css:
/* Mobile */
@media (max-width: 767px) { 

    selector .grecaptcha-badge { 
        z-index: 0
    }

    selector #form-field-form_email_desk,
    selector #form-field-form_regiao_desk,
    selector button#newsletter-send-buttom {
        font-size: 0.8rem;
        height: 2.7rem;
    }


    selector #newsletter-send-buttom-desktop {
        background: transparent;
        border: 2px solid white;
    }

    selector button {
        color: white !important;
    }

    selector button:target,
    selector button:active{
        color: rgb(130, 36, 23) !important;
        background: white !important;
    }
}

/* Desktop */
@media (min-width: 768px) { 
    selector .elementor-form-fields-wrapper{
        display: flex;
        flex-direction: column;
    }

selector .grecaptcha-badge { 
        z-index: -9999;
        display: none !important;
    }
}

selector .grecaptcha-badge { 
    z-index: 0
}

selector #form-field-form_regiao,
selector #form-field-form_email,
selector button#newsletter-send-buttom {
    font-size: 0.8rem;
    height: 2.7rem;
}


selector #newsletter-send-buttom {
    background: transparent;
    border: 2px solid white;
}

selector button {
    color: white !important;
}

selector button:target,
selector button:active{
    color: rgb(130, 36, 23) !important;
    background: white !important;
}

selector ul {
        display: grid;
        grid-template-columns: repeat(2, 1fr);
        min-width: fit-content;
}
.selector li {
  display: inline-block;
}
selector .elementor-nav-menu ul {display:none !important;
}

selector .elementor-item-active {
    text-decoration: underline;
}

.selector a:hover {
    font-weight: bold;
    transition-duration: 0;
}
